// --- applying a theme ---
function applyTheme(id) {
  var t = THEMES[id];
  if (!t) return;
  currentThemeId = id;
  ivRoot.setAttribute('data-theme', id);

  document.getElementById('iv-brand-name').innerHTML = t.brand.name;
  document.getElementById('iv-brand-sub').innerHTML = t.brand.sub;

  if (!documentLoaded) {
    document.getElementById('iv-hero-eyebrow').innerHTML = t.hero.eyebrow;
    heroTitle.innerHTML = t.hero.title;
    heroLead.innerHTML = t.hero.lead;
  }

  document.getElementById('iv-banner-tag').innerHTML = t.banner.tag;
  document.getElementById('iv-banner-heading').innerHTML = t.banner.heading;

  document.getElementById('iv-dz-title').innerHTML = t.dropzone.title;
  document.getElementById('iv-dz-sub').innerHTML = t.dropzone.sub;

  document.getElementById('iv-gallery-tag').innerHTML = t.gallery.tag;
  t.gallery.items.forEach(function (item, i) {
    var img = document.getElementById('iv-gallery-img-' + (i + 1));
    var cap = document.getElementById('iv-gallery-cap-' + (i + 1));
    if (img) { img.setAttribute('src', item.src); img.setAttribute('alt', item.alt || ''); }
    if (cap) { cap.textContent = item.cap; }
  });

  document.getElementById('iv-footer-brand').innerHTML = t.footer.brand;
  document.getElementById('iv-footer-tagline').innerHTML = t.footer.tagline;
  document.getElementById('iv-footer-address').innerHTML = t.footer.addressHTML;
  document.getElementById('iv-footer-hours').innerHTML = t.footer.hoursHTML;
  document.getElementById('iv-footer-copyright').innerHTML = t.footer.copyright;

  if (lastRenderedSections && lastRenderedSections.length) {
    ivImageCursor = 0;
    renderSections(lastRenderedSections, lastRenderedMeta || {});
  }

  renderThemeOptions();
}

// --- hamburger + panel wiring ---
var themeBtn = document.getElementById('iv-theme-btn');
var themePanel = document.getElementById('iv-theme-panel');
var themeOptionsEl = document.getElementById('iv-theme-options');

themeBtn.addEventListener('click', function (e) {
  e.stopPropagation();
  themePanel.classList.toggle('open');
  themeBtn.setAttribute('aria-expanded', themePanel.classList.contains('open'));
});
document.addEventListener('click', function (e) {
  if (!themePanel.contains(e.target) && e.target !== themeBtn) {
    themePanel.classList.remove('open');
    themeBtn.setAttribute('aria-expanded', 'false');
  }
});
document.addEventListener('keydown', function (e) {
  if (e.key === 'Escape') {
    themePanel.classList.remove('open');
    themeBtn.setAttribute('aria-expanded', 'false');
  }
});

function renderThemeOptions() {
  themeOptionsEl.innerHTML = '';
  Object.keys(THEMES).forEach(function (id) {
    var t = THEMES[id];
    var btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'iv-theme-option' + (id === currentThemeId ? ' active' : '');
    btn.innerHTML =
      '<span class="iv-theme-swatch" style="background:' + t.colors.red + '"></span>' +
      '<span class="name">' + t.label + '</span>' +
      '<span class="check">\u2713</span>';
    btn.addEventListener('click', function () {
      applyTheme(id);
      themePanel.classList.remove('open');
    });
    themeOptionsEl.appendChild(btn);
  });
}

renderThemeOptions();
